from starlette.types import ASGIApp, Receive, Scope, Send

class RawASGIMiddleware:
    def __init__(self, app: ASGIApp):
        self.app = app

    async def __call__(self, scope: Scope, receive: Receive, send: Send):
        if scope["type"] == "http":
            # Mutate scope, wrap receive/send as needed
            await self.app(scope, receive, send)
        else:
            # Pass through non-HTTP (websocket, lifespan)
            await self.app(scope, receive, send)

app.add_middleware(RawASGIMiddleware)

from starlette.middleware.base import BaseHTTPMiddleware
from jose import jwt, JWTError

UNPROTECTED_PATHS = {"/health", "/auth/token", "/docs", "/openapi.json"}

class AuthContextMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        request.state.user = None  # Default: unauthenticated

        if request.url.path not in UNPROTECTED_PATHS:
            auth_header = request.headers.get("Authorization", "")
            if auth_header.startswith("Bearer "):
                token = auth_header[7:]
                try:
                    payload = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
                    request.state.user = payload
                except JWTError:
                    pass  # Endpoints enforce auth via Depends() — middleware only extracts

        return await call_next(request)

from starlette.middleware.base import BaseHTTPMiddleware
from fastapi.responses import JSONResponse

class RequestSizeLimitMiddleware(BaseHTTPMiddleware):
    def __init__(self, app, max_body_size: int = 10 * 1024 * 1024):  # 10MB default
        super().__init__(app)
        self.max_body_size = max_body_size

    async def dispatch(self, request: Request, call_next):
        content_length = request.headers.get("content-length")

        if content_length and int(content_length) > self.max_body_size:
            return JSONResponse(
                status_code=413,
                content={"detail": f"Request body exceeds {self.max_body_size} bytes"}
            )

        return await call_next(request)

app.add_middleware(RequestSizeLimitMiddleware, max_body_size=5 * 1024 * 1024)

import os
from starlette.middleware.base import BaseHTTPMiddleware
from fastapi.responses import JSONResponse

class MaintenanceModeMiddleware(BaseHTTPMiddleware):
    BYPASS_PATHS = {"/health"}

    async def dispatch(self, request: Request, call_next):
        if os.environ.get("MAINTENANCE_MODE") == "true":
            if request.url.path not in self.BYPASS_PATHS:
                return JSONResponse(
                    status_code=503,
                    content={"detail": "Service temporarily unavailable for maintenance"},
                    headers={"Retry-After": "300"}
                )
        return await call_next(request)

