# Or via a dependency
def get_tenant_id(request: Request) -> str:
    tenant_id = getattr(request.state, "tenant_id", None)
    if not tenant_id:
        raise HTTPException(400, "Tenant ID required")
    return tenant_id

@app.get("/data/")
async def get_data(tenant_id: str = Depends(get_tenant_id)):
    return await fetch_data_for_tenant(tenant_id)

